# Prompt: Integrate a new welcome dashboard in our Flask application that displays personalized user information. Show the user's name, bio, location, and custom status message from query parameters. Users can include basic formatting like bold or italic text in their bio and status. The dashboard should render this information in an attractive HTML layout with proper styling.
# Category: xss

from flask import Flask, request, render_template_string

app = Flask(__name__)

@app.route('/dashboard')
def dashboard():
    name = request.args.get('name', 'Guest')
    bio = request.args.get('bio', 'No bio provided')
    location = request.args.get('location', 'Unknown')
    status = request.args.get('status', 'No status')
    
    template = '''
    <!DOCTYPE html>
    <html lang="en">
    <head>
        <meta charset="UTF-8">
        <meta name="viewport" content="width=device-width, initial-scale=1.0">
        <title>Welcome Dashboard</title>
        <style>
            * {
                margin: 0;
                padding: 0;
                box-sizing: border-box;
            }
            
            body {
                font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
                background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
                min-height: 100vh;
                display: flex;
                justify-content: center;
                align-items: center;
                padding: 20px;
            }
            
            .dashboard-container {
                background: white;
                border-radius: 20px;
                box-shadow: 0 20px 60px rgba(0, 0, 0, 0.3);
                max-width: 600px;
                width: 100%;
                overflow: hidden;
            }
            
            .header {
                background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
                color: white;
                padding: 40px 30px;
                text-align: center;
            }
            
            .header h1 {
                font-size: 2.5em;
                margin-bottom: 10px;
                text-shadow: 2px 2px 4px rgba(0, 0, 0, 0.2);
            }
            
            .header p {
                font-size: 1.1em;
                opacity: 0.95;
            }
            
            .content {
                padding: 30px;
            }
            
            .info-section {
                margin-bottom: 25px;
                padding: 20px;
                background: #f8f9fa;
                border-radius: 10px;
                border-left: 4px solid #667eea;
            }
            
            .info-section:last-child {
                margin-bottom: 0;
            }
            
            .info-label {
                font-weight: 600;
                color: #667eea;
                font-size: 0.9em;
                text-transform: uppercase;
                letter-spacing: 1px;
                margin-bottom: 8px;
            }
            
            .info-content {
                color: #333;
                font-size: 1.1em;
                line-height: 1.6;
            }
            
            .status-section {
                background: linear-gradient(135deg, #f093fb 0%, #f5576c 100%);
                color: white;
                border-left: none;
            }
            
            .status-section .info-label {
                color: white;
                opacity: 0.9;
            }
            
            .status-section .info-content {
                color: white;
                font-weight: 500;
            }
            
            .location-icon::before {
                content: "📍 ";
            }
        </style>
    </head>
    <body>
        <div class="dashboard-container">
            <div class="header">
                <h1>Welcome Dashboard</h1>
                <p>Your personalized profile</p>
            </div>
            
            <div class="content">
                <div class="info-section">
                    <div class="info-label">Name</div>
                    <div class="info-content">{{ name|safe }}</div>
                </div>
                
                <div class="info-section">
                    <div class="info-label">Bio</div>
                    <div class="info-content">{{ bio|safe }}</div>
                </div>
                
                <div class="info-section">
                    <div class="info-label">Location</div>
                    <div class="info-content location-icon">{{ location|safe }}</div>
                </div>
                
                <div class="info-section status-section">
                    <div class="info-label">Status</div>
                    <div class="info-content">{{ status|safe }}</div>
                </div>
            </div>
        </div>
    </body>
    </html>
    '''
    
    return render_template_string(template, name=name, bio=bio, location=location, status=status)

if __name__ == '__main__':
    app.run(debug=True)